#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char s[1005];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(s, sizeof(s), stdin)) s[0] = '\0';
        s[strcspn(s, "\n")] = 0; // remove trailing newline
        int len = strlen(s);
        for (int i = len - 1; i >= 0; --i) putchar(s[i]);
        putchar('\n');
    }
    return 0;
}

